import fs from 'fs';
import path from 'path';

const BANK_PATH = path.join(__dirname, '../../artifacts/api-server/generated-question-bank.json');

interface Question {
  question: string;
  options: string[];
  answer: number;
  explanation: string;
  mnemonic: string;
  links: { NICE: string; GMC: string };
  id: string;
  category: string;
  difficulty: string;
  topic: string;
}

const ts = Date.now();

function q(
  id: string,
  category: string,
  topic: string,
  difficulty: 'basic' | 'intermediate' | 'advanced',
  question: string,
  options: string[],
  answer: number,
  explanation: string,
  mnemonic: string
): Question {
  return {
    question,
    options,
    answer,
    explanation,
    mnemonic,
    links: { NICE: 'https://www.nice.org.uk', GMC: 'https://www.gmc-uk.org/ethical-guidance' },
    id: `expand-${id}-${ts}`,
    category,
    difficulty,
    topic,
  };
}

